sp_angular_provider.script:
function scmTableDataService() {
	"use strict";

	function nextRequestId(currentRequestId) {
		return (currentRequestId || 0) + 1;
	}

	function isLatestRequest(requestId, latestRequestId) {
		return requestId === latestRequestId;
	}

	function computeTotalPages(totalRecords, limit) {
		var parsedLimit = parseInt(limit, 10) || 0;
		return parsedLimit > 0 ? Math.ceil((totalRecords || 0) / parsedLimit) : 0;
	}

	function getTableData(options) {
		options = options || {};

		var server = options.server;
		if (!server) {
			return Promise.reject(new Error("Missing server"));
		}

		return server.get({
			action: "getTableData",
			transactionId: options.transactionId,
			tableProviderScriptInclude: options.tableProviderScriptInclude,
			page: options.page,
			filters: options.filters || [],
			includeTotalRecords: !!options.includeTotalRecords,
		});
	}

	function getTotalRecords(options) {
		options = options || {};

		var server = options.server;
		if (!server) {
			return Promise.reject(new Error("Missing server"));
		}

		return server.get({
			action: "getTotalRecords",
			transactionId: options.transactionId,
			tableProviderScriptInclude: options.tableProviderScriptInclude,
			filters: options.filters || [],
		});
	}

	return {
		nextRequestId: nextRequestId,
		isLatestRequest: isLatestRequest,
		computeTotalPages: computeTotalPages,
		getTableData: getTableData,
		getTotalRecords: getTotalRecords,
	};
}
